        dp = [[INF] * 26 for _ in range(n)]
        for c in range(26):
            dp[0][c] = 0 if ord(word[0]) - 97 == c else 1

        for i in range(1, n):
            prev_word_val = ord(word[i]) - 97
            for c in range(26):
                cost = 0 if c == prev_word_val else 1
                best = INF
                # Allowed predecessors p satisfy abs(c - p) >= 2
                for p in range(26):
                    if abs(c - p) >= 2:
                        if dp[i - 1][p] < best:
                            best = dp[i - 1][p]
                dp[i][c] = best + cost

        return min(dp[n - 1])
